async function grantAndEmail(payload) {
  const { email, name, waitlist_id } = payload;

  // 1. Auto-generate a password
  const password = generatePassword();

  // 2. Create the streamer account
  const authR = await fetch(`${process.env.SUPABASE_URL}/auth/v1/admin/users`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'apikey': process.env.SUPABASE_SECRET_KEY, 'Authorization': `Bearer ${process.env.SUPABASE_SECRET_KEY}` },
    body: JSON.stringify({ email, password, email_confirm: true })
  });
  const authData = await authR.json();
  if (authData.error && !authData.error.message.includes('already')) {
    return { statusCode: 200, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ error: authData.error.message }) };
  }

  // 3. Add to streamers table
  await fetch(`${sbBase()}/streamers`, {
    method: 'POST', headers: sbHeaders(),
    body: JSON.stringify({ email, access_type: 'beta', expires_at: null })
  });

  // 4. Remove from waitlist
  if (waitlist_id) {
    await fetch(`${sbBase()}/waitlist?id=eq.${waitlist_id}`, { method: 'DELETE', headers: sbHeaders() });
  }

  // 5. Send welcome email via Resend
  const html = welcomeEmailHtml(name, email, password);
  const emailR = await fetch('https://api.resend.com/emails', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${process.env.RESEND_API_KEY}`
    },
    body: JSON.stringify({
      from: 'FantasyFM <welcome@fantasyfm.io>',
      to: [email],
      subject: `You're in! Your FantasyFM streamer access 🎮`,
      html
    })
  });
  const emailData = await emailR.json();
  if (emailData.error) {
    return { statusCode: 200, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ error: 'Account created but email failed: ' + emailData.error.message }) };
  }

  return { statusCode: 200, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ ok: true, password }) };
}

async function updateStreamer(payload) {
  const r = await fetch(`${sbBase()}/streamers?id=eq.${payload.id}`, {
    method: 'PATCH', headers: sbHeaders(),
    body: JSON.stringify({ access_type: payload.access_type, expires_at: payload.expires_at })
  });
  const data = await r.json();
  return { statusCode: 200, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(data) };
}

async function removeStreamer(payload) {
  await fetch(`${sbBase()}/streamers?id=eq.${payload.id}`, { method: 'DELETE', headers: sbHeaders() });
  return { statusCode: 200, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ ok: true }) };
}

async function handleSupabase(body) {
  const base = sbBase();
  const headers = sbHeaders();
  const { action, payload } = body;
  let result;

  try {
    if (action === 'create_session') {
      // Use user's own JWT so auth.uid() resolves and user_id is set by DB default
      const sessionHeaders = payload.user_jwt
        ? { 'Content-Type': 'application/json', 'apikey': process.env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${payload.user_jwt}`, 'Prefer': 'return=representation' }
        : headers;
      const body = { id: payload.id, is_live: true };
      // Only pass user_id explicitly if no JWT (fallback to service role path)
      if (!payload.user_jwt && payload.user_id) body.user_id = payload.user_id;
      const r = await fetch(`${base}/sessions`, { method: 'POST', headers: sessionHeaders, body: JSON.stringify(body) });
      result = await r.json();
    }
    else if (action === 'save_roster') {
      await fetch(`${base}/roster?session_id=eq.${payload.session_id}`, { method: 'DELETE', headers });
      if (payload.players.length > 0) {
        const r = await fetch(`${base}/roster`, { method: 'POST', headers, body: JSON.stringify(payload.players.map(p => ({ session_id: payload.session_id, name: p.name, pos: p.pos }))) });
        result = await r.json();
      } else result = [];
      await ablyPublish(payload.session_id, 'state_changed', { type: 'roster' });
    }
    else if (action === 'get_roster') {
      const r = await fetch(`${base}/roster?session_id=eq.${payload.session_id}&select=name,pos`, { headers });
      result = await r.json();
    }
    else if (action === 'upsert_viewer') {
      const r = await fetch(`${base}/viewers?session_id=eq.${payload.session_id}&viewer_name=eq.${encodeURIComponent(payload.viewer_name)}`, { headers });
      const existing = await r.json();
      if (existing.length > 0) {
        const upd = await fetch(`${base}/viewers?session_id=eq.${payload.session_id}&viewer_name=eq.${encodeURIComponent(payload.viewer_name)}`, { method: 'PATCH', headers, body: JSON.stringify({ pick_def: payload.pick_def, pick_mid: payload.pick_mid, pick_att: payload.pick_att, pick_cap: payload.pick_cap || null, locked: payload.locked, events_at_lock: payload.events_at_lock||0, platform: payload.platform || null, oauth_id: payload.oauth_id || null, avatar_url: payload.avatar_url || null }) });
        result = await upd.json();
      } else {
        const ins = await fetch(`${base}/viewers`, { method: 'POST', headers, body: JSON.stringify({ session_id: payload.session_id, viewer_name: payload.viewer_name, pick_def: payload.pick_def, pick_mid: payload.pick_mid, pick_att: payload.pick_att, pick_cap: payload.pick_cap || null, locked: payload.locked, events_at_lock: payload.events_at_lock||0, platform: payload.platform || null, oauth_id: payload.oauth_id || null, avatar_url: payload.avatar_url || null, total_points: 0 }) });
        result = await ins.json();
      }
      await ablyPublish(payload.session_id, 'state_changed', { type: 'viewer', viewer_name: payload.viewer_name });
    }
    else if (action === 'get_viewers') {
      const r = await fetch(`${base}/viewers?session_id=eq.${payload.session_id}&select=viewer_name,pick_def,pick_mid,pick_att,pick_cap,locked,total_points,platform,oauth_id,avatar_url,events_at_lock`, { headers });
      result = await r.json();
    }
    else if (action === 'add_event') {
      // Server-side validation before writing to DB
      const allowedPos = ['DEF','MID','ATT'];
      const allowedEvents = ['goal','assist','clean_sheet','motm','rating','yellow_card','red_card','manual_adjust'];
      const pts = Number(payload.points);
      if (!allowedPos.includes(payload.pos)) throw new Error('Invalid pos');
      if (!allowedEvents.includes(payload.event_type)) throw new Error('Invalid event_type');
      if (!isFinite(pts) || Math.abs(pts) > 100) throw new Error('Invalid points value');
      if (!payload.session_id || !payload.player_name) throw new Error('Missing required fields');
      const safeName = String(payload.player_name).replace(/[<>"'`]/g,'').slice(0,60);
      const r = await fetch(`${base}/events`, { method: 'POST', headers, body: JSON.stringify({ session_id: payload.session_id, player_name: safeName, pos: payload.pos, event_type: payload.event_type, points: pts }) });
      result = await r.json();
      await ablyPublish(payload.session_id, 'state_changed', { type: 'event', player_name: safeName, event_type: payload.event_type, points: pts });
    }
    else if (action === 'delete_last_event') {
      const r = await fetch(`${base}/events?session_id=eq.${payload.session_id}&order=id.desc&limit=1`, { headers });
      const events = await r.json();
      if (events.length > 0) {
        await fetch(`${base}/events?id=eq.${events[0].id}`, { method: 'DELETE', headers });
        result = events[0];
        await ablyPublish(payload.session_id, 'state_changed', { type: 'event_deleted' });
      } else result = null;
    }
    else if (action === 'get_events') {
      const r = await fetch(`${base}/events?session_id=eq.${payload.session_id}&select=player_name,pos,event_type,points,created_at&order=id.asc`, { headers });
      result = await r.json();
    }
    else if (action === 'get_session') {
      const r = await fetch(`${base}/sessions?id=eq.${payload.session_id}&select=id,is_live`, { headers });
      const sessions = await r.json();
      result = sessions[0] || null;
    }
    else if (action === 'add_waitlist') {
      // Check for duplicate
      const check = await fetch(`${base}/waitlist?email=eq.${encodeURIComponent(payload.email)}&select=id`, { headers });
      const existing = await check.json();
      if (existing.length > 0) { result = { error: 'duplicate' }; }
      else {
        const r = await fetch(`${base}/waitlist`, { method: 'POST', headers, body: JSON.stringify({ name: payload.name, email: payload.email, channel: payload.channel || null }) });
        result = await r.json();
      }
    }
    else if (action === 'get_waitlist') {
      const r = await fetch(`${base}/waitlist?order=created_at.asc&select=id,name,email,channel,created_at`, { headers });
      result = await r.json();
    }
    else if (action === 'remove_waitlist') {
      await fetch(`${base}/waitlist?id=eq.${payload.id}`, { method: 'DELETE', headers });
      result = { ok: true };
    }
    else if (action === 'submit_bug') {
      const r = await fetch(`${base}/bug_reports`, { method: 'POST', headers, body: JSON.stringify({ streamer_email: payload.streamer_email, category: payload.category, description: payload.description, steps: payload.steps || null, resolved: false }) });
      result = await r.json();
    }
    else if (action === 'get_bugs') {
      const r = await fetch(`${base}/bug_reports?order=created_at.desc&select=id,streamer_email,category,description,steps,resolved,created_at`, { headers });
      result = await r.json();
    }
    else if (action === 'resolve_bug') {
      await fetch(`${base}/bug_reports?id=eq.${payload.id}`, { method: 'PATCH', headers, body: JSON.stringify({ resolved: payload.resolved }) });
      result = { ok: true };
    }
    else if (action === 'reset_session') {
      await fetch(`${base}/events?session_id=eq.${payload.session_id}`, { method: 'DELETE', headers });
      await fetch(`${base}/viewers?session_id=eq.${payload.session_id}`, { method: 'DELETE', headers });
      await fetch(`${base}/roster?session_id=eq.${payload.session_id}`, { method: 'DELETE', headers });
      await fetch(`${base}/sessions?id=eq.${payload.session_id}`, { method: 'DELETE', headers });
      await ablyPublish(payload.session_id, 'state_changed', { type: 'reset' });
      result = { ok: true };
    }
    return { statusCode: 200, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(result) };
  } catch (err) {
    return { statusCode: 500, body: JSON.stringify({ error: err.message }) };
  }
}
